+import React from 'react';
+
+// Character component renders a character sprite with 1px dark outline and drop shadow
+function Character({ sprite, x, y, zIndex }) {
+  const style = {
+    position: 'absolute',
+    left: x,
+    top: y,
+    zIndex: zIndex,
+    filter: 'drop-shadow(2px 2px 2px rgba(0,0,0,0.5))',
+    // Outline using text-shadow trick for images
+    // We create 4 shadows around the image to simulate 1px outline
+    // This works well for pixel art characters
+    imageRendering: 'pixelated',
+    boxShadow:
+      '1px 0 0 #000, -1px 0 0 #000, 0 1px 0 #000, 0 -1px 0 #000',
+  };
+
+  return <img src={sprite} alt="character" style={style} />;
+}
+
+export default Character;
