+import Character from './Character';
+
+// Sort characters by zIndex ascending for proper z-sorting
+function GameScene({ characters }) {
+  const sortedChars = [...characters].sort((a, b) => a.zIndex - b.zIndex);
+
+  return (
+    <div
+      className="game-scene"
+      style={{ position: 'relative', width: 800, height: 600 }}
+    >
+      {sortedChars.map((char) => (
+        <Character
+          key={char.id}
+          sprite={char.sprite}
+          x={char.x}
+          y={char.y}
+          zIndex={char.zIndex}
+        />
+      ))}
+    </div>
+  );
+}
+
+export default GameScene;
